using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

namespace GlobalErrorHandling;

/// <summary>
/// Maps known exception types to RFC 7807 Problem Details responses.
/// Registered via AddExceptionHandler so no per-endpoint try-catch is needed.
/// </summary>
public sealed class GlobalExceptionHandler(ILogger<GlobalExceptionHandler> logger)
    : IExceptionHandler
{
    public async ValueTask<bool> TryHandleAsync(
        HttpContext httpContext,
        Exception exception,
        CancellationToken cancellationToken)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException   => (StatusCodes.Status404NotFound,    "Not Found"),
            ArgumentException      => (StatusCodes.Status400BadRequest,  "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "Internal Server Error")
        };

        logger.LogError(exception, "Unhandled exception ({Type})", exception.GetType().Name);

        var problem = new ProblemDetails
        {
            Status = statusCode,
            Title  = title,
            // Only surface the message for client errors; hide details for 500s
            Detail = statusCode < 500 ? exception.Message : "An unexpected error occurred."
        };

        httpContext.Response.StatusCode = statusCode;
        await httpContext.Response.WriteAsJsonAsync(problem, cancellationToken);
        return true; // signal that the exception was handled
    }
}

using GlobalErrorHandling;

var builder = WebApplication.CreateBuilder(args);

// RFC 7807 Problem Details support
builder.Services.AddProblemDetails();

// Register the global exception handler
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();

var app = builder.Build();

// Activate the exception handler middleware (must be early in the pipeline)
app.UseExceptionHandler();

// --- Sample endpoints to demonstrate each mapping ---

app.MapGet("/items/{id:int}", (int id) =>
{
    if (id == 0)  throw new KeyNotFoundException($"Item {id} was not found.");
    if (id < 0)   throw new ArgumentException("Id must be positive.");
    if (id == 99) throw new InvalidOperationException("Item 99 is in a conflicting state.");
    if (id == 13) throw new Exception("Something went terribly wrong."); // 500

    return Results.Ok(new { Id = id, Name = $"Item-{id}" });
});

app.Run();

